<template>
  <div class="add-task">
    <div class="add-task__wrapper container">
      <div class="add-task__header">
        <div class="add-task__title">Добавление задачи</div>
        <button
          class="add-task__close"
          @click="$emit('closeModalAddTask')"
        ></button>
      </div>
      <input
        type="text"
        class="add-task__title-inp"
        placeholder="Задача . . ."
        v-model="task.title"
      />
      <div class="add-task__date">
        <div class="add-task__date-title">До какого выполнить</div>
        <div class="add-task__date-inp">
          <input type="date" v-model="task.dateTime.date" />
          <input type="time" v-model="task.dateTime.time" />
        </div>
      </div>
      <div class="add-task__subtask">
        <button class="add-task__subtask-add" @click="addSubTaskInp">
          Добавить Подзадачу
        </button>
        <div class="add-task__subtasks">
          <div
            class="add-task__subtask-inp"
            v-for="(subTaskInp, index) in subTasksInp"
            :key="index"
          >
            <input
              type="text"
              placeholder="Подзадача"
              v-model="subTasksInp[index]"
            />
            <button @click="removeSubTask(index)"></button>
          </div>
        </div>
      </div>
      <button class="add-task__add" @click="addTask()">
        Опубликовать задачу
      </button>
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      tasks: [],
      task: {
        title: "",
        completed: false,
        dateTime: {
          date: "",
          time: "",
        },
        subTasks: [],
      },
      subTasksInp: [],
    };
  },
  computed: {
    allTasks() {
      return this.$store.getters.tasks;
    },
  },
  mounted() {
    if (this.allTasks) {
      this.tasks = this.allTasks;
    }
  },
  methods: {
    addSubTaskInp() {
      this.subTasksInp.push("");
      console.log(this.subTasksInp);
    },
    removeSubTask(index) {
      console.log(index);
      this.subTasksInp.splice(index, 1);
    },
    rnadomId() {
      const date = new Date();
      return (
          date.getFullYear() *
          date.getDate() *
          date.getHours() *
          date.getMinutes() *
          date.getSeconds() *
          date.getMilliseconds()
      );
    },
    addTask() {
      if (this.task.title) {
        this.subTasksInp.forEach((item) => {
          this.task.subTasks.push({
            title: item,
            completed: false,
          });
        });

        this.tasks.unshift({
          title: this.task.title,
          completed: false,
          dateTime: {
            date: this.task.dateTime.date,
            time: this.task.dateTime.time,
          },
          subTasks: this.task.subTasks,
          idTask: this.rnadomId(),
        });

        console.log(this.rnadomId())

        this.$store.commit("addTasks", this.tasks);
        this.$emit("addTasks", this.tasks);
        localStorage.setItem("tasks", JSON.stringify(this.tasks));

        this.task.title = "";
        this.task.completed = false;
        this.task.dateTime.date = "";
        this.task.dateTime.time = "";
        this.task.subTasks = [];
        this.subTasksInp = [];
        this.$emit("closeModalAddTask");
      }
    },
  },
};
</script>

<style lang="scss" scoped>
$blue: #1771f1;
$blue-hover: #095ed6;
$dark: #131313;

.add-task {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: #030303;
  color: #fff;
  z-index: 100;
  overflow: scroll;
  padding-bottom: 20px;

  &::-webkit-scrollbar {
    width: 0;
  }

  .add-task__wrapper {
    height: 100%;
    min-height: 500px;
  }

  .add-task__header {
    width: 100%;
    margin-top: 15px;
    display: flex;
    align-items: center;
    justify-content: space-between;

    .add-task__title {
      font-size: 17px;
    }

    .add-task__close {
      width: 20px;
      height: 20px;
      padding: 0;
      background: transparent;
      border-radius: 0;
      background-image: url(../assets/icons/close.svg);
      background-size: 80%;
      background-position: center;
      background-repeat: no-repeat;
    }
  }

  .add-task__title-inp {
    width: 100%;
    margin-top: 20px;
  }

  .add-task__date {
    width: 100%;
    margin-top: 20px;

    .add-task__date-title {
      font-size: 12px;
    }

    .add-task__date-inp {
      width: 100%;
      margin-top: 5px;
      display: flex;
      align-items: center;
      justify-content: space-between;

      input {
        width: 49%;
      }
    }
  }

  .add-task__subtask {
    margin-top: 20px;

    .add-task__subtask-add {
      width: 100%;
      height: 30px;
      padding: 0;
      border-radius: 5px;
      background: $dark;
      font-size: 14px;
      font-weight: 400;
    }

    .add-task__subtasks {
      margin-top: 10px;
      display: flex;
      flex-direction: column;

      .add-task__subtask-inp {
        display: flex;
        align-items: center;
        border-radius: 10px;
        background-color: #131313;

        &:not(:first-child) {
          margin-top: 5px;
        }

        input {
          width: 100%;
          height: 40px;
        }

        button {
          width: 40px;
          height: 40px;
          border-radius: 0;
          background-color: transparent;
          background-image: url(../assets/icons/close.svg);
          background-size: 30%;
          background-repeat: no-repeat;
          background-position: center;
        }
      }
    }
  }

  .add-task__add {
    margin-top: 20px;
    width: 100%;
    height: 35px;
  }
}
</style>