<template>
  <div class="task">
    <div class="task__wrapper container">
      <div class="task__header">
        <div class="task__close" @click="$emit('closeModalTask')"></div>
        <div class="task__params">
          <div
              class="task__param"
              @click="toggleFavorite"
              v-if="!addedFavorites && $route.path != '/favorites'"
              :style="{backgroundImage:'url(' + require('@/assets/icons/favorites.svg') + ')',}"
          ></div>
          <div
              class="task__param"
              @click="toggleFavorite"
              v-else-if="addedFavorites && $route.path != '/favorites'"
              :style="{backgroundImage:'url(' + require('@/assets/icons/favorites-acive.svg') + ')',}"
          ></div>
          <div
              class="task__param"
              @click="$emit('removeTask', taskIndex)"
              :style="{
              backgroundImage:
                'url(' + require('@/assets/icons/remove.svg') + ')',
            }"
          ></div>
        </div>
      </div>
      <div
          class="task__date"
          v-if="tasks[taskIndex].dateTime.date || tasks[taskIndex].dateTime.time"
      >
        {{ tasks[taskIndex].dateTime.date }} |
        {{ tasks[taskIndex].dateTime.time }}
      </div>
      <h2 class="task__title"
          :class="{ 'text-completed': tasks[taskIndex].subTasks.every(elem => elem.completed == true) }">
        {{ tasks[taskIndex].title }}</h2>

      <ul class="task__subtasks">
        <li
            class="task__subtask"
            v-for="(subTask, index) in tasks[taskIndex].subTasks"
            :key="'sub' + index"
        >
          <input
              type="checkbox"
              @click="completedSubTask(index)"
              v-model="
              tasks[taskIndex].subTasks[index].completed ? 'checked' : ''
            "
              :id="taskIndex + index"
          />
          <label
              :for="taskIndex + index"
              :class="{
              'text-completed':
                tasks[taskIndex].subTasks[index].completed,
            }"
          >{{ subTask.title }}</label
          >
        </li>
      </ul>
    </div>
  </div>
</template>

<script>
export default {
  props: {
    taskIndex: Number,
    allTasks: [],
    favorites: Boolean,
  },
  data() {
    return {
      tasks: [],
      addedFavorites: false,
    };
  },
  computed: {
    allFavorites() {
      return this.$store.getters.favorites;
    },
  },
  mounted() {
    this.tasks = this.allTasks;
    if (this.allFavorites.find(item => item.idTask == this.tasks[this.taskIndex].idTask)) {
      this.addedFavorites = true;
    }
    console.log(this.$route.path)
  },
  methods: {
    completedSubTask(index) {
      this.tasks[this.taskIndex].subTasks[index].completed =
          !this.tasks[this.taskIndex].subTasks[index].completed;
      this.$emit('saveTasks', this.tasks)
    },
    toggleFavorite() {
      if (!this.allFavorites.find(item => item.idTask == this.tasks[this.taskIndex].idTask)) {
        this.$emit('addFavorites', this.taskIndex)
        this.addedFavorites = true;
      } else {
        this.$emit('removeFavorites', this.taskIndex)
        this.addedFavorites = false;
      }
    }
  },
};
</script>

<style lang="scss" scoped>
$blue: #1771f1;
$blue-hover: #095ed6;
$dark: #131313;

.task {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: #030303;
  color: #fff;
  z-index: 100;
  overflow: scroll;
  padding-bottom: 20px;

  &::-webkit-scrollbar {
    width: 0;
  }

  .task__wrapper {
    height: 100%;
    min-height: 500px;
  }

  .task__header {
    width: 100%;
    height: 50px;
    display: flex;
    justify-content: space-between;
    align-items: center;

    .task__close {
      width: 17px;
      height: 17px;
      background-image: url(../assets/icons/left-arrow.svg);
      background-size: 100%;
      background-position: center;
      background-repeat: no-repeat;
    }

    .task__params {
      display: flex;
      align-items: center;

      .task__param {
        width: 20px;
        height: 20px;
        background-size: 100%;
        background-position: center;
        background-repeat: no-repeat;

        &:not(:last-child) {
          margin-right: 13px;
        }
      }
    }
  }

  .task__date {
    margin-top: 13px;
    font-size: 11px;
  }

  .task__title {
    margin-top: 5px;
    font-size: 23px;
  }

  .task__subtasks {
    margin-top: 15px;
    list-style: none;

    .task__subtask {
      display: flex;
      // align-items: center;

      &:not(:first-child) {
        margin-top: 10px;
      }

      input {
        // width: 70px;
        // height: 70px;
      }

      label {
        margin-left: 10px;
        font-size: 16px;
      }
    }
  }
}
</style>